// AST Type Definitions

const SourceFile = struct {
    items: []const Item,
};

const Item = union(enum) {
    zig_line: ZigLine,
    event_decl: EventDecl,
    proc_decl: ProcDecl,
    flow: Flow,
    import_decl: ImportDecl,
    subflow_impl: SubflowImpl,
    label_decl: LabelDecl,
    module_decl: ModuleDecl,
    event_tap: EventTap,
    host_type_decl: HostTypeDecl,
};

const ZigLine = struct {
    content: []const u8,
};

const ModuleDecl = struct {
    logical_name: []const u8,
    canonical_path: []const u8,
    items: []const Item,
    is_system: bool,
};

const EventDecl = struct {
    path: []const []const u8,
    input: Shape,
    branches: []const Branch,
    is_public: bool,
    is_implicit_flow: bool,
    annotations: []const []const u8,
};

const HostTypeDecl = struct {
    name: []const u8,
    shape: Shape,
};

const Shape = struct {
    fields: []const Field,
};

const Field = struct {
    name: []const u8,
    type: []const u8,
    is_flow_ast: bool,
    is_source: bool,
    is_file: bool,
    is_embed_file: bool,
    phantom: ?[]const u8,
    expression: ?*const void = null,
    expression_str: ?[]const u8 = null,
    owns_expression: bool = false,
};

const Branch = struct {
    name: []const u8,
    payload: Shape,
    is_deferred: bool,
};

const SuperShape = struct {
    branches: []const BranchVariant,
};

const BranchVariant = struct {
    name: []const u8,
    payload: Shape,
    sources: []const DottedPath,
};

const ProcDecl = struct {
    path: []const []const u8,
    body: []const u8,  // The Zig code body
    inline_flows: []const Flow = &.{},
    annotations: []const []const u8 = &.{},
};

const Flow = struct {
    invocation: Invocation,
    continuations: []const Continuation,
    pre_label: ?[]const u8,
    post_label: ?[]const u8,
    super_shape: ?*const SuperShape = null,
};

const Invocation = struct {
    path: []const []const u8,
    args: []const Arg,
};

const Arg = struct {
    name: []const u8,
    value: []const u8,
    ast_value: ?*const FlowAST,
    ast_value_items: ?[]const Item,
};

const FlowAST = struct {
    items: []const Item,  // Reference into ProgramAST
};

const Expression = struct {};

const BindingType = enum {
    branch_payload,
    transition,
};

const Continuation = struct {
    branch: []const u8,
    binding: ?[]const u8,
    binding_type: BindingType = .branch_payload,
    condition: ?[]const u8,
    condition_expr: ?*Expression = null,
    pipeline: []const Step,
    indent: usize,
    nested: []const Continuation,
};

const Step = union(enum) {
    invocation: Invocation,
    label_apply: []const u8,
    label_with_invocation: struct {
        label: []const u8,
        invocation: Invocation,
    },
    terminal: void,
    deref: struct {
        target: []const u8,
        args: ?[]const Arg,
    },
    branch_constructor: BranchConstructor,
};

const BranchConstructor = struct {
    branch_name: []const u8,
    fields: []const Field,
    has_expressions: bool = false,
};

const ImportDecl = struct {
    path: []const u8,
    name: ?[]const u8,
};

const SubflowImpl = struct {
    event_path: []const []const u8,
    body: SubflowBody,
};

const SubflowBody = union(enum) {
    flow: Flow,
    immediate: BranchConstructor,
};

const LabelDecl = struct {
    name: []const u8,
    continuations: []const Continuation,
};

const EventTap = struct {
    source: ?DottedPath,
    destination: ?DottedPath,
    is_input_tap: bool = false,
    continuations: []const Continuation,
    annotations: []const []const u8 = &.{},
};

const DottedPath = struct {
    segments: []const []const u8,
};

