// Metacircular Code Generator

const compiler_emit_zig = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) { emitted: struct { code: []const u8 } };
    pub fn handler(e: Input) Output {

    // @compileLog("EMITTER: Received AST with", e.ast.items.len, "items");

    const MAX_SIZE = 64 * 1024; // 64KB buffer

    // Sentinel value used to indicate we're generating code inside a tap function
    // (not a real flow number). This prevents infinite recursion when tap functions
    // invoke events - we don't inject taps inside tap functions themselves.
    const TAP_FUNCTION_CONTEXT: usize = 9999;

    var buffer: [MAX_SIZE]u8 = undefined;
    var pos: usize = 0;
    
    // Helper function for writing strings
    const writeStr = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, str: []const u8) usize {
            if (p + str.len >= MAX_SIZE) return p;
            @memcpy(buf[p..p + str.len], str);
            return p + str.len;
        }
    }.call;
    
    // Helper function for equality comparison
    const eql = struct {
        fn call(a: []const u8, b: []const u8) bool {
            if (a.len != b.len) return false;
            for (a, 0..) |char, i| {
                if (char != b[i]) return false;
            }
            return true;
        }
    }.call;

    // Helper function to reindent text with additional spaces
    const reindentText = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, text: []const u8, additional_indent: []const u8) usize {
            var text_pos = p;
            var i: usize = 0;
            
            while (i < text.len) {
                // Find the end of the current line
                var line_end = i;
                while (line_end < text.len and text[line_end] != '\n') {
                    line_end += 1;
                }
                
                // Write additional indentation if the line is not empty
                if (line_end > i) {
                    // Check if line has content (not just whitespace)
                    var has_content = false;
                    var j = i;
                    while (j < line_end) : (j += 1) {
                        if (text[j] != ' ' and text[j] != '\t') {
                            has_content = true;
                            break;
                        }
                    }
                    
                    if (has_content) {
                        text_pos = writeStr(buf, text_pos, additional_indent);
                    }
                }
                
                // Write the line content
                if (line_end > i) {
                    @memcpy(buf[text_pos..text_pos + (line_end - i)], text[i..line_end]);
                    text_pos += line_end - i;
                }
                
                // Write the newline if present
                if (line_end < text.len) {
                    buf[text_pos] = '\n';
                    text_pos += 1;
                }
                
                i = line_end + 1;
            }
            
            return text_pos;
        }
    }.call;
    
    // Helper function to generate continuation body recursively
    const generateContinuationBody = struct {
        fn call(buf: *[MAX_SIZE]u8, p: usize, cont: anytype, indent: []const u8, ast_items: anytype, depth: usize, flow_num: usize) usize {
            var inner_pos = p;
            
            // Process the pipeline steps
            if (cont.pipeline.len > 0) {
                for (cont.pipeline) |step| {
                    switch (step) {
                        .invocation => |inv| {
                            // Generate nested event invocation
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "const nested_result_");
                            var depth_buf: [32]u8 = undefined;
                            const depth_str = std.fmt.bufPrint(&depth_buf, "{}", .{depth}) catch "0";
                            inner_pos = writeStr(buf, inner_pos, depth_str);
                            inner_pos = writeStr(buf, inner_pos, " = ");
                            
                            // Check if event is in a module
                            var event_module: ?[]const u8 = null;
                            for (ast_items) |item| {
                                switch (item) {
                                    .module_decl => |module| {
                                        for (module.items) |mod_item| {
                                            switch (mod_item) {
                                                .event_decl => |event| {
                                                    if (event.path.len == inv.path.len) {
                                                        var matches = true;
                                                        for (event.path, 0..) |seg, j| {
                                                            if (!eql(seg, inv.path[j])) {
                                                                matches = false;
                                                                break;
                                                            }
                                                        }
                                                        if (matches) {
                                                            event_module = module.logical_name;
                                                            break;
                                                        }
                                                    }
                                                },
                                                else => {},
                                            }
                                        }
                                        if (event_module != null) break;
                                    },
                                    else => {},
                                }
                            }
                            
                            // Write event path
                            if (event_module) |mod| {
                                inner_pos = writeStr(buf, inner_pos, mod);
                                inner_pos = writeStr(buf, inner_pos, ".");
                                inner_pos = writeStr(buf, inner_pos, inv.path[inv.path.len - 1]);
                            } else {
                                for (inv.path, 0..) |segment, idx| {
                                    if (idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                    inner_pos = writeStr(buf, inner_pos, segment);
                                }
                            }
                            inner_pos = writeStr(buf, inner_pos, ".handler(.{");
                            
                            // Write arguments
                            for (inv.args, 0..) |arg, idx| {
                                if (idx > 0) inner_pos = writeStr(buf, inner_pos, ", ");
                                inner_pos = writeStr(buf, inner_pos, " .");
                                inner_pos = writeStr(buf, inner_pos, arg.name);
                                inner_pos = writeStr(buf, inner_pos, " = ");
                                inner_pos = writeStr(buf, inner_pos, arg.value);
                            }
                            inner_pos = writeStr(buf, inner_pos, " });\n");
                            
                            // Generate switch for nested continuations if any
                            if (cont.nested.len > 0) {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "switch (nested_result_");
                                inner_pos = writeStr(buf, inner_pos, depth_str);
                                inner_pos = writeStr(buf, inner_pos, ") {\n");
                                
                                // Generate nested continuations
                                for (cont.nested) |nested| {
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    .");
                                    inner_pos = writeStr(buf, inner_pos, nested.branch);
                                    inner_pos = writeStr(buf, inner_pos, " => ");
                                    
                                    if (nested.binding) |binding| {
                                        inner_pos = writeStr(buf, inner_pos, "|");
                                        inner_pos = writeStr(buf, inner_pos, binding);
                                        inner_pos = writeStr(buf, inner_pos, "| {\n");
                                    } else {
                                        inner_pos = writeStr(buf, inner_pos, "{\n");
                                    }

                                    // INJECT TAP CALLS for nested event transitions
                                    // Skip tap injection if we're generating a tap function itself
                                    if (flow_num != TAP_FUNCTION_CONTEXT) {
                                        // For each tap that matches: inv.path -> * | nested.branch
                                        var tap_idx: usize = 0;
                                        for (ast_items) |tap_item| {
                                            switch (tap_item) {
                                                .event_tap => |tap| {
                                                    // Check if this tap matches current transition
                                                    // Source must match nested event invocation (inv.path)
                                                    var source_matches = false;
                                                    if (tap.source) |src| {
                                                        if (src.segments.len == inv.path.len) {
                                                            source_matches = true;
                                                            for (src.segments, 0..) |segment, idx| {
                                                                if (!eql(segment, inv.path[idx])) {
                                                                    source_matches = false;
                                                                    break;
                                                                }
                                                            }
                                                        }
                                                    } else {
                                                        // null source = wildcard (*)
                                                        source_matches = true;
                                                    }

                                                    // Check if tap has continuation for this branch
                                                    var has_branch = false;
                                                    if (source_matches) {
                                                        for (tap.continuations) |tap_cont| {
                                                            if (eql(tap_cont.branch, nested.branch)) {
                                                                has_branch = true;
                                                                break;
                                                            }
                                                        }
                                                    }

                                                    // If matches, inject tap call
                                                    if (has_branch) {
                                                        // Check what parameter type tap needs
                                                        var tap_needs_transition = false;
                                                        var tap_needs_branch_payload = false;
                                                        for (tap.continuations) |tap_cont| {
                                                            if (tap_cont.binding_type == .transition) {
                                                                tap_needs_transition = true;
                                                                break;
                                                            } else if (tap_cont.binding) |_| {
                                                                tap_needs_branch_payload = true;
                                                                break;
                                                            }
                                                        }

                                                        inner_pos = writeStr(buf, inner_pos, indent);
                                                        inner_pos = writeStr(buf, inner_pos, "        __tap");
                                                        var tap_idx_buf: [32]u8 = undefined;
                                                        const tap_idx_str = std.fmt.bufPrint(&tap_idx_buf, "{}", .{tap_idx}) catch "ERROR";
                                                        inner_pos = writeStr(buf, inner_pos, tap_idx_str);
                                                        inner_pos = writeStr(buf, inner_pos, "(");

                                                        // Pass appropriate parameter based on tap binding type
                                                        if (tap_needs_transition) {
                                                            inner_pos = writeStr(buf, inner_pos, ".{ .source = \"");
                                                            // Write source event name (from inv.path)
                                                            for (inv.path, 0..) |seg, seg_idx| {
                                                                if (seg_idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                                                inner_pos = writeStr(buf, inner_pos, seg);
                                                            }
                                                            inner_pos = writeStr(buf, inner_pos, "\", .branch = \"");
                                                            inner_pos = writeStr(buf, inner_pos, nested.branch);
                                                            inner_pos = writeStr(buf, inner_pos, "\", .destination = ");

                                                            // Determine destination from nested continuation pipeline
                                                            var has_destination = false;
                                                            if (nested.pipeline.len > 0) {
                                                                switch (nested.pipeline[0]) {
                                                                    .invocation => |next_inv| {
                                                                        // Check if it's not terminal (_)
                                                                        if (next_inv.path.len > 0 and !eql(next_inv.path[0], "_")) {
                                                                            has_destination = true;
                                                                            inner_pos = writeStr(buf, inner_pos, "\"");
                                                                            for (next_inv.path, 0..) |seg, seg_idx| {
                                                                                if (seg_idx > 0) inner_pos = writeStr(buf, inner_pos, ".");
                                                                                inner_pos = writeStr(buf, inner_pos, seg);
                                                                            }
                                                                            inner_pos = writeStr(buf, inner_pos, "\"");
                                                                        }
                                                                    },
                                                                    else => {},
                                                                }
                                                            }
                                                            if (!has_destination) {
                                                                inner_pos = writeStr(buf, inner_pos, "null");
                                                            }
                                                            inner_pos = writeStr(buf, inner_pos, " }");
                                                        } else if (tap_needs_branch_payload) {
                                                            // Pass the branch payload binding from the nested continuation
                                                            if (nested.binding) |binding| {
                                                                inner_pos = writeStr(buf, inner_pos, binding);
                                                            }
                                                        }

                                                        inner_pos = writeStr(buf, inner_pos, ");\n");
                                                    }

                                                    tap_idx += 1;
                                                },
                                                else => {},
                                            }
                                        }
                                    } // End of tap injection if statement

                                    // Recursively generate nested body with increased indent
                                    var deeper_indent_buf: [64]u8 = undefined;
                                    var deeper_indent_len: usize = 0;
                                    @memcpy(deeper_indent_buf[0..indent.len], indent);
                                    deeper_indent_len = indent.len;
                                    const extra = "        ";
                                    @memcpy(deeper_indent_buf[deeper_indent_len..deeper_indent_len + extra.len], extra);
                                    deeper_indent_len += extra.len;
                                    const deeper_indent = deeper_indent_buf[0..deeper_indent_len];
                                    
                                    inner_pos = call(buf, inner_pos, nested, deeper_indent, ast_items, depth + 1, flow_num);
                                    
                                    inner_pos = writeStr(buf, inner_pos, indent);
                                    inner_pos = writeStr(buf, inner_pos, "    },\n");
                                }
                                
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "}\n");
                            } else {
                                // No nested continuations, just consume the result
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = nested_result_");
                                inner_pos = writeStr(buf, inner_pos, depth_str);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                        },
                        .terminal => {
                            // Terminal step - suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "// Terminal\n");
                        },
                        .label_with_invocation => |label_inv| {
                            // Tail call back to labeled flow with new arguments
                            // Suppress unused binding warning if there is one
                            if (cont.binding) |binding| {
                                inner_pos = writeStr(buf, inner_pos, indent);
                                inner_pos = writeStr(buf, inner_pos, "_ = &");
                                inner_pos = writeStr(buf, inner_pos, binding);
                                inner_pos = writeStr(buf, inner_pos, ";\n");
                            }
                            // Generate: return @call(.always_tail, flow0_loop, .{ arg1, arg2, ... });
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "return @call(.always_tail, flow");
                            var label_num_buf: [32]u8 = undefined;
                            const label_num_str = std.fmt.bufPrint(&label_num_buf, "{}", .{flow_num}) catch "ERROR";
                            inner_pos = writeStr(buf, inner_pos, label_num_str);
                            inner_pos = writeStr(buf, inner_pos, "_");
                            inner_pos = writeStr(buf, inner_pos, label_inv.label);
                            inner_pos = writeStr(buf, inner_pos, ", .{ ");

                            // Pass arguments from the jump invocation
                            for (label_inv.invocation.args, 0..) |arg, arg_idx| {
                                if (arg_idx > 0) {
                                    inner_pos = writeStr(buf, inner_pos, ", ");
                                }
                                inner_pos = writeStr(buf, inner_pos, arg.value);
                            }

                            inner_pos = writeStr(buf, inner_pos, " });\n");
                        },
                        else => {
                            inner_pos = writeStr(buf, inner_pos, indent);
                            inner_pos = writeStr(buf, inner_pos, "// TODO: Handle other step types\n");
                        },
                    }
                }
            } else {
                // Empty pipeline
                inner_pos = writeStr(buf, inner_pos, indent);
                inner_pos = writeStr(buf, inner_pos, "// Empty continuation\n");
            }
            
            return inner_pos;
        }
    }.call;
    
    
    // Generate header
    pos = writeStr(&buffer, pos, "// Generated by Koru compiler.emit.zig event - METACIRCULAR!\n");
    pos = writeStr(&buffer, pos, "\n");
    
    // Check if there's a user-defined main function or any flows/events
    var has_user_main = false;
    var has_flows = false;
    var has_events = false;
    
    for (e.ast.items) |item| {
        switch (item) {
            .zig_line => |line| {
                // Simple check: if line starts with "pub fn main"
                if (line.content.len >= 11 and eql(line.content[0..11], "pub fn main")) {
                    has_user_main = true;
                }
            },
            .flow => {
                has_flows = true;
            },
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.len == 0 or !eql(event.path[0], "compiler")) {
                    has_events = true;
                }
            },
            else => {},
        }
    }
    
    // If user defined main and no Koru features, just output as-is
    if (has_user_main and !has_flows and !has_events) {
        // Just output zig_lines directly without module struct
        for (e.ast.items) |item| {
            switch (item) {
                .zig_line => |line| {
                    pos = writeStr(&buffer, pos, line.content);
                    pos = writeStr(&buffer, pos, "\n");
                },
                else => {},
            }
        }
        // Return early - no need for further processing
        const final_code = buffer[0..pos];
        return .{ .emitted = .{ .code = final_code } };
    }
    
    // First, generate imported module structs from ModuleDecl items
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => |module| {
                pos = writeStr(&buffer, pos, "pub const ");
                pos = writeStr(&buffer, pos, module.logical_name);
                pos = writeStr(&buffer, pos, " = struct {\n");
                
                // Process all items in the module
                for (module.items) |mod_item| {
                    switch (mod_item) {
                        .zig_line => |line| {
                            pos = writeStr(&buffer, pos, "    ");
                            pos = writeStr(&buffer, pos, line.content);
                            pos = writeStr(&buffer, pos, "\n");
                        },
                        .event_decl => |event| {
                            // Skip compiler events (they're only for compile-time use)
                            // TODO: Use event.is_compiler_internal flag once available
                            if (event.path.len > 0 and eql(event.path[0], "compiler")) {
                                continue;
                            }

                            // MARKER: UPDATED_EMITTER_2025_09_30
                            // Skip comptime-only events (with FlowAST, ProgramAST, or Source parameters)
                            var is_comptime_only = false;
                            for (event.input.fields) |field| {
                                if (field.is_flow_ast or field.is_source) {
                                    is_comptime_only = true;
                                    break;
                                }
                                if (eql(field.type, "ProgramAST") or eql(field.type, "SourceFile")) {
                                    is_comptime_only = true;
                                    break;
                                }
                            }
                            if (is_comptime_only) {
                                continue;
                            }

                            // Generate event struct
                            pos = writeStr(&buffer, pos, "    pub const ");
                            pos = writeStr(&buffer, pos, event.path[event.path.len - 1]);
                            pos = writeStr(&buffer, pos, " = struct {\n");
                            
                            // Input struct
                            pos = writeStr(&buffer, pos, "        pub const Input = struct {\n");
                            for (event.input.fields) |field| {
                                pos = writeStr(&buffer, pos, "            ");
                                pos = writeStr(&buffer, pos, field.name);
                                pos = writeStr(&buffer, pos, ": ");
                                if (field.is_file or field.is_embed_file) {
                                    pos = writeStr(&buffer, pos, "[]const u8");
                                } else {
                                    pos = writeStr(&buffer, pos, field.type);
                                }
                                pos = writeStr(&buffer, pos, ",\n");
                            }
                            pos = writeStr(&buffer, pos, "        };\n");
                            
                            // Output type - void for events with no branches
                            if (event.branches.len == 0) {
                                // Void event - no output
                                pos = writeStr(&buffer, pos, "        pub const Output = void;\n");
                            } else {
                                // Output union for events with branches
                                pos = writeStr(&buffer, pos, "        pub const Output = union(enum) {\n");
                                for (event.branches) |branch| {
                                    pos = writeStr(&buffer, pos, "            ");
                                    // TEMP: Unconditionally escape ALL branch names to test mechanism
                                    pos = writeStr(&buffer, pos, "@\"");
                                    pos = writeStr(&buffer, pos, branch.name);
                                    pos = writeStr(&buffer, pos, "\"");
                                    pos = writeStr(&buffer, pos, ": struct {\n");
                                    for (branch.payload.fields) |field| {
                                        pos = writeStr(&buffer, pos, "                ");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ": ");
                                        pos = writeStr(&buffer, pos, field.type);
                                        pos = writeStr(&buffer, pos, ",\n");
                                    }
                                    pos = writeStr(&buffer, pos, "            },\n");
                                }
                                pos = writeStr(&buffer, pos, "        };\n");
                            }
                            
                            // Handler function
                            pos = writeStr(&buffer, pos, "        pub fn handler(e: Input) Output {\n");
                            
                            // Find implementation in the same module
                            var found_impl = false;
                            for (module.items) |impl_item| {
                                switch (impl_item) {
                                    .proc_decl => |proc| {
                                        if (proc.path.len == event.path.len) {
                                            var matches = true;
                                            for (proc.path, 0..) |seg, j| {
                                                if (!eql(seg, event.path[j])) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            if (matches) {
                                                pos = writeStr(&buffer, pos, "            _ = &e;\n");

                                                // Emit proc body with proper indentation
                                                pos = reindentText(&buffer, pos, proc.body, "        ");
                                                pos = writeStr(&buffer, pos, "\n");
                                                found_impl = true;
                                                break;
                                            }
                                        }
                                    },
                                    else => {},
                                }
                            }
                            
                            if (!found_impl) {
                                if (event.branches.len > 0) {
                                    pos = writeStr(&buffer, pos, "            return .{ .");
                                    pos = writeStr(&buffer, pos, event.branches[0].name);
                                    pos = writeStr(&buffer, pos, " = .{} };\n");
                                } else {
                                    pos = writeStr(&buffer, pos, "            return undefined;\n");
                                }
                            }
                            
                            pos = writeStr(&buffer, pos, "        }\n");
                            pos = writeStr(&buffer, pos, "    };\n");
                        },
                        else => {},
                    }
                }
                
                // Close the module struct
                pos = writeStr(&buffer, pos, "};\n\n");
            },
            else => {},
        }
    }
    
    // Now generate the main module struct
    pos = writeStr(&buffer, pos, "pub const main_module = struct {\n");
    
    // First pass: Collect zig_lines (imports) - inside the module struct!
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .zig_line => |line| {
                pos = writeStr(&buffer, pos, "    ");
                pos = writeStr(&buffer, pos, line.content);
                pos = writeStr(&buffer, pos, "\n");
            },
            else => {},
        }
    }

    // Collect all annotation combinations from taps that use transition bindings
    // We need to generate a Transition type for each unique annotation set
    var has_base_transition = false;  // Transition with no annotations
    var has_profiling_transition = false;  // Transition_profiling

    for (e.ast.items) |item| {
        switch (item) {
            .event_tap => |tap| {
                for (tap.continuations) |cont| {
                    if (cont.binding_type == .transition) {
                        // Check what annotations this tap has
                        if (tap.annotations.len == 0) {
                            has_base_transition = true;
                        } else {
                            // Check for profiling annotation
                            for (tap.annotations) |ann| {
                                if (eql(ann, "profiling")) {
                                    has_profiling_transition = true;
                                }
                            }
                        }
                    }
                }
            },
            else => {},
        }
    }

    // Generate base Transition type if needed
    if (has_base_transition) {
        pos = writeStr(&buffer, pos, "    // Transition meta-type for event taps\n");
        pos = writeStr(&buffer, pos, "    const Transition = struct {\n");
        pos = writeStr(&buffer, pos, "        source: []const u8,\n");
        pos = writeStr(&buffer, pos, "        branch: []const u8,\n");
        pos = writeStr(&buffer, pos, "        destination: ?[]const u8,\n");
        pos = writeStr(&buffer, pos, "    };\n");
        pos = writeStr(&buffer, pos, "\n");
    }

    // Generate Transition_profiling type if needed
    if (has_profiling_transition) {
        pos = writeStr(&buffer, pos, "    // Transition meta-type with profiling data\n");
        pos = writeStr(&buffer, pos, "    const Transition_profiling = struct {\n");
        pos = writeStr(&buffer, pos, "        source: []const u8,\n");
        pos = writeStr(&buffer, pos, "        branch: []const u8,\n");
        pos = writeStr(&buffer, pos, "        destination: ?[]const u8,\n");
        pos = writeStr(&buffer, pos, "        duration_ns: ?u64,  // Added by [profiling] annotation\n");
        pos = writeStr(&buffer, pos, "    };\n");
        pos = writeStr(&buffer, pos, "\n");
    }

    // Second pass: Generate inline flow helper functions
    // These are module-level functions that wrap inline flows from procs
    var inline_flow_counter: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,
            .proc_decl => |proc| {
                if (proc.inline_flows.len > 0) {
                    // Generate helper function for each inline flow
                    for (proc.inline_flows) |inline_flow| {
                        inline_flow_counter += 1;

                        // Function signature: fn __inline_flow_N(args: EventName.Input) ReturnType
                        pos = writeStr(&buffer, pos, "    fn __inline_flow_");
                        var counter_buf: [32]u8 = undefined;
                        const counter_str = std.fmt.bufPrint(&counter_buf, "{d}", .{inline_flow_counter}) catch "0";
                        pos = writeStr(&buffer, pos, counter_str);
                        pos = writeStr(&buffer, pos, "(args: ");

                        // Input type from invoked event
                        for (inline_flow.invocation.path, 0..) |seg, idx| {
                            if (idx > 0) pos = writeStr(&buffer, pos, ".");
                            pos = writeStr(&buffer, pos, seg);
                        }
                        pos = writeStr(&buffer, pos, ".Input) ");

                        // Output type from super_shape or proc's event
                        // For inline flows with branch constructors, return type comes from the proc's event
                        for (proc.path, 0..) |seg, idx| {
                            if (idx > 0) pos = writeStr(&buffer, pos, ".");
                            pos = writeStr(&buffer, pos, seg);
                        }
                        pos = writeStr(&buffer, pos, ".Output {\n");

                        // Call the invoked event handler
                        pos = writeStr(&buffer, pos, "        const result = ");
                        for (inline_flow.invocation.path, 0..) |seg, idx| {
                            if (idx > 0) pos = writeStr(&buffer, pos, ".");
                            pos = writeStr(&buffer, pos, seg);
                        }
                        pos = writeStr(&buffer, pos, ".handler(args);\n");

                        // Generate switch statement to map branches to constructors
                        pos = writeStr(&buffer, pos, "        return switch (result) {\n");

                        for (inline_flow.continuations) |cont| {
                            pos = writeStr(&buffer, pos, "            .");
                            pos = writeStr(&buffer, pos, cont.branch);
                            pos = writeStr(&buffer, pos, " => ");

                            // Check if binding is actually used in any expression
                            var binding_used = false;
                            if (cont.binding) |binding| {
                                if (cont.pipeline.len > 0) {
                                    switch (cont.pipeline[0]) {
                                        .branch_constructor => |bc| {
                                            for (bc.fields) |field| {
                                                if (field.expression_str) |expr| {
                                                    if (std.mem.indexOf(u8, expr, binding) != null) {
                                                        binding_used = true;
                                                        break;
                                                    }
                                                }
                                            }
                                        },
                                        else => {},
                                    }
                                }

                                // Only capture binding if it's used
                                if (binding_used) {
                                    pos = writeStr(&buffer, pos, "|");
                                    pos = writeStr(&buffer, pos, binding);
                                    pos = writeStr(&buffer, pos, "| ");
                                }
                            }

                            // Generate branch constructor
                            if (cont.pipeline.len > 0) {
                                switch (cont.pipeline[0]) {
                                    .branch_constructor => |bc| {
                                        pos = writeStr(&buffer, pos, ".{ .");
                                        pos = writeStr(&buffer, pos, bc.branch_name);
                                        pos = writeStr(&buffer, pos, " = .{");

                                        for (bc.fields, 0..) |field, idx| {
                                            if (idx > 0) pos = writeStr(&buffer, pos, ", ");
                                            pos = writeStr(&buffer, pos, " .");
                                            pos = writeStr(&buffer, pos, field.name);
                                            pos = writeStr(&buffer, pos, " = ");

                                            // Use expression_str for the field value
                                            if (field.expression_str) |expr| {
                                                pos = writeStr(&buffer, pos, expr);
                                            } else {
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                        }

                                        pos = writeStr(&buffer, pos, " } }");
                                    },
                                    else => {},
                                }
                            } else {
                                // Empty pipeline (discard case): generate empty block
                                pos = writeStr(&buffer, pos, "{}");
                            }

                            pos = writeStr(&buffer, pos, ",\n");
                        }

                        pos = writeStr(&buffer, pos, "        };\n");
                        pos = writeStr(&buffer, pos, "    }\n");
                    }
                }
            },
            else => {},
        }
    }

    // Second pass: Generate host type declarations
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,
            .host_type_decl => |host_type| {
                // Generate host type as struct
                pos = writeStr(&buffer, pos, "    const ");
                pos = writeStr(&buffer, pos, host_type.name);
                pos = writeStr(&buffer, pos, " = struct {\n");

                // Generate fields
                for (host_type.shape.fields) |field| {
                    pos = writeStr(&buffer, pos, "        ");
                    pos = writeStr(&buffer, pos, field.name);
                    pos = writeStr(&buffer, pos, ": ");
                    pos = writeStr(&buffer, pos, field.type);
                    pos = writeStr(&buffer, pos, ",\n");
                }

                pos = writeStr(&buffer, pos, "    };\n");
            },
            else => {},
        }
    }

    // Third pass: Generate events (only local ones, not imported)
    for (e.ast.items) |item| {
        switch (item) {
            .module_decl => continue,  // Skip module declarations
            .event_decl => |event| {
                // Skip compiler events
                if (event.path.len > 0 and eql(event.path[0], "compiler")) {
                    continue;
                }

                // Skip comptime-only events (with FlowAST, ProgramAST, or Source parameters)
                var is_comptime_only = false;
                for (event.input.fields) |field| {
                    if (field.is_flow_ast or field.is_source) {
                        is_comptime_only = true;
                        break;
                    }
                    if (eql(field.type, "ProgramAST") or eql(field.type, "SourceFile")) {
                        is_comptime_only = true;
                        break;
                    }
                }
                if (is_comptime_only) {
                    continue;
                }

                // Write the event with proper indentation (we're inside main_module)
                pos = writeStr(&buffer, pos, "    pub const ");
                pos = writeStr(&buffer, pos, event.path[event.path.len - 1]);
                pos = writeStr(&buffer, pos, " = struct {\n");
                
                // Input struct
                pos = writeStr(&buffer, pos, "        pub const Input = struct {\n");
                for (event.input.fields) |field| {
                    pos = writeStr(&buffer, pos, "            ");
                    pos = writeStr(&buffer, pos, field.name);
                    pos = writeStr(&buffer, pos, ": ");
                    if (field.is_file or field.is_embed_file) {
                        pos = writeStr(&buffer, pos, "[]const u8");
                    } else {
                        pos = writeStr(&buffer, pos, field.type);
                    }
                    pos = writeStr(&buffer, pos, ",\n");
                }
                pos = writeStr(&buffer, pos, "        };\n");
                
                // Output type - void for events with no branches
                if (event.branches.len == 0) {
                    // Void event - no output
                    pos = writeStr(&buffer, pos, "        pub const Output = void;\n");
                } else {
                    // Output union for events with branches
                    pos = writeStr(&buffer, pos, "        pub const Output = union(enum) {\n");
                    for (event.branches) |branch| {
                        pos = writeStr(&buffer, pos, "            ");
                        // TEMP: Unconditionally escape ALL branch names
                        pos = writeStr(&buffer, pos, "@\"");
                        pos = writeStr(&buffer, pos, branch.name);
                        pos = writeStr(&buffer, pos, "\"");
                        pos = writeStr(&buffer, pos, ": struct {\n");
                        for (branch.payload.fields) |field| {
                            pos = writeStr(&buffer, pos, "                ");
                            pos = writeStr(&buffer, pos, field.name);
                            pos = writeStr(&buffer, pos, ": ");
                            pos = writeStr(&buffer, pos, field.type);
                            pos = writeStr(&buffer, pos, ",\n");
                        }
                        pos = writeStr(&buffer, pos, "            },\n");
                    }
                    pos = writeStr(&buffer, pos, "        };\n");
                }
                
                // Handler function
                pos = writeStr(&buffer, pos, "        pub fn handler(e: Input) Output {\n");
                
                // Find implementation
                var found_impl = false;
                for (e.ast.items) |impl_item| {
                    switch (impl_item) {
                        .proc_decl => |proc| {
                            if (proc.path.len == event.path.len) {
                                var matches = true;
                                for (proc.path, 0..) |seg, j| {
                                    if (!eql(seg, event.path[j])) {
                                        matches = false;
                                        break;
                                    }
                                }
                                if (matches) {
                                    // Generate source marker for proc
                                    pos = writeStr(&buffer, pos, "            // >>> PROC: ");
                                    for (proc.path, 0..) |seg, idx| {
                                        if (idx > 0) pos = writeStr(&buffer, pos, ".");
                                        pos = writeStr(&buffer, pos, seg);
                                    }
                                    pos = writeStr(&buffer, pos, "\n");

                                    // Generate implicit input bindings - destructure all input fields
                                    // This makes procs consistent with subflows by providing direct access to input fields
                                    for (event.input.fields) |field| {
                                        pos = writeStr(&buffer, pos, "            const ");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, " = e.");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ";\n");
                                    }
                                    // Suppress unused variable warnings for all destructured fields
                                    for (event.input.fields) |field| {
                                        pos = writeStr(&buffer, pos, "            _ = &");
                                        pos = writeStr(&buffer, pos, field.name);
                                        pos = writeStr(&buffer, pos, ";\n");
                                    }

                                    // Keep _ = &e for backwards compatibility if proc uses e directly
                                    pos = writeStr(&buffer, pos, "            _ = &e;\n");

                                    // Emit proc body with proper indentation (add 8 more spaces to existing 4)
                                    pos = reindentText(&buffer, pos, proc.body, "        ");
                                    pos = writeStr(&buffer, pos, "\n");
                                    found_impl = true;
                                    break;
                                }
                            }
                        },
                        .subflow_impl => |subflow| {
                            if (subflow.event_path.len == event.path.len) {
                                var matches = true;
                                for (subflow.event_path, 0..) |seg, j| {
                                    if (!eql(seg, event.path[j])) {
                                        matches = false;
                                        break;
                                    }
                                }
                                if (matches) {
                                    switch (subflow.body) {
                                        .immediate => |bc| {
                                            // Generate implicit input bindings for immediate subflows
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            const ");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, " = e.");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            // Suppress unused variable warnings
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            _ = &");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            pos = writeStr(&buffer, pos, "            return .{ .");
                                            pos = writeStr(&buffer, pos, bc.branch_name);
                                            pos = writeStr(&buffer, pos, " = .{");
                                            for (bc.fields, 0..) |field, k| {
                                                if (k > 0) pos = writeStr(&buffer, pos, ", ");
                                                pos = writeStr(&buffer, pos, " .");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, " = ");
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                            pos = writeStr(&buffer, pos, " } };\n");
                                        },
                                        .flow => |flow| {
                                            // Generate implicit input bindings for consistency with procs
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            const ");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, " = e.");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            // Suppress unused variable warnings
                                            for (event.input.fields) |field| {
                                                pos = writeStr(&buffer, pos, "            _ = &");
                                                pos = writeStr(&buffer, pos, field.name);
                                                pos = writeStr(&buffer, pos, ";\n");
                                            }
                                            pos = writeStr(&buffer, pos, "            _ = &e;\n");
                                            
                                            // Generate the invocation of the inner event
                                            pos = writeStr(&buffer, pos, "            const result = ");
                                            
                                            // Write event path (e.g., "transform")
                                            for (flow.invocation.path, 0..) |segment, idx| {
                                                if (idx > 0) pos = writeStr(&buffer, pos, ".");
                                                pos = writeStr(&buffer, pos, segment);
                                            }
                                            pos = writeStr(&buffer, pos, ".handler(.{");
                                            
                                            // Write arguments, mapping from input parameters
                                            for (flow.invocation.args, 0..) |arg, idx| {
                                                if (idx > 0) pos = writeStr(&buffer, pos, ", ");
                                                pos = writeStr(&buffer, pos, " .");
                                                pos = writeStr(&buffer, pos, arg.name);
                                                pos = writeStr(&buffer, pos, " = e.");
                                                // Map the arg value to the input field
                                                // arg.value should be the input field name
                                                pos = writeStr(&buffer, pos, arg.value);
                                            }
                                            pos = writeStr(&buffer, pos, " });\n");
                                            
                                            // Generate switch statement to map branches
                                            pos = writeStr(&buffer, pos, "            switch (result) {\n");
                                            
                                            // Generate each continuation as a case
                                            for (flow.continuations) |cont| {
                                                pos = writeStr(&buffer, pos, "                .");
                                                pos = writeStr(&buffer, pos, cont.branch);
                                                pos = writeStr(&buffer, pos, " => ");
                                                
                                                // Check if there's a binding
                                                if (cont.binding) |binding| {
                                                    pos = writeStr(&buffer, pos, "|");
                                                    pos = writeStr(&buffer, pos, binding);
                                                    pos = writeStr(&buffer, pos, "| {\n");
                                                } else {
                                                    pos = writeStr(&buffer, pos, "{\n");
                                                }
                                                
                                                // Generate the return statement with branch constructor
                                                // For now, assume single step in pipeline is branch constructor
                                                if (cont.pipeline.len > 0) {
                                                    switch (cont.pipeline[0]) {
                                                        .branch_constructor => |bc| {
                                                            pos = writeStr(&buffer, pos, "                    return .{ .");
                                                            pos = writeStr(&buffer, pos, bc.branch_name);
                                                            pos = writeStr(&buffer, pos, " = .{");
                                                            
                                                            // Generate fields
                                                            for (bc.fields, 0..) |field, k| {
                                                                if (k > 0) pos = writeStr(&buffer, pos, ", ");
                                                                pos = writeStr(&buffer, pos, " .");
                                                                pos = writeStr(&buffer, pos, field.name);
                                                                pos = writeStr(&buffer, pos, " = ");
                                                                
                                                                // The field.type contains the expression to evaluate
                                                                // Check if it references the binding or parent input
                                                                // Simple heuristic: if it starts with binding name, use as-is
                                                                // Otherwise, it might be a parent input field, prefix with "e."
                                                                var needs_e_prefix = true;
                                                                if (cont.binding) |binding| {
                                                                    // Check if field.type starts with binding name
                                                                    if (field.type.len >= binding.len) {
                                                                        var field_matches = true;
                                                                        for (binding, 0..) |ch, idx| {
                                                                            if (field.type[idx] != ch) {
                                                                                field_matches = false;
                                                                                break;
                                                                            }
                                                                        }
                                                                        // Also check that it's followed by . or end
                                                                        if (field_matches and (field.type.len == binding.len or field.type[binding.len] == '.')) {
                                                                            needs_e_prefix = false;
                                                                        }
                                                                    }
                                                                }
                                                                
                                                                // Check for literal values (numbers, strings)
                                                                if (field.type.len > 0) {
                                                                    const first_char = field.type[0];
                                                                    if (first_char == '"' or (first_char >= '0' and first_char <= '9') or first_char == '-') {
                                                                        needs_e_prefix = false;
                                                                    }
                                                                }
                                                                
                                                                if (needs_e_prefix) {
                                                                    pos = writeStr(&buffer, pos, "e.");
                                                                }
                                                                pos = writeStr(&buffer, pos, field.type);
                                                            }
                                                            pos = writeStr(&buffer, pos, " } };\n");
                                                        },
                                                        else => {
                                                            // Fallback for non-branch-constructor steps
                                                            pos = writeStr(&buffer, pos, "                    return undefined; // TODO: handle other step types\n");
                                                        },
                                                    }
                                                } else {
                                                    // No pipeline steps - shouldn't happen but handle gracefully
                                                    pos = writeStr(&buffer, pos, "                    return undefined; // Empty pipeline\n");
                                                }
                                                
                                                pos = writeStr(&buffer, pos, "                },\n");
                                            }
                                            
                                            pos = writeStr(&buffer, pos, "            }\n");
                                        },
                                    }
                                    found_impl = true;
                                    break;
                                }
                            }
                        },
                        else => {},
                    }
                }
                
                if (!found_impl) {
                    // Add unused parameter suppression
                    pos = writeStr(&buffer, pos, "            _ = e;\n");
                    
                    if (event.branches.len > 0) {
                        // Return with proper field values
                        pos = writeStr(&buffer, pos, "            return .{ .");
                        pos = writeStr(&buffer, pos, event.branches[0].name);
                        pos = writeStr(&buffer, pos, " = .{");
                        
                        // Generate default values for each field in the branch
                        for (event.branches[0].payload.fields) |field| {
                            pos = writeStr(&buffer, pos, " .");
                            pos = writeStr(&buffer, pos, field.name);
                            pos = writeStr(&buffer, pos, " = ");
                            
                            // Generate appropriate default based on type
                            if (eql(field.type, "i32")) {
                                pos = writeStr(&buffer, pos, "0");
                            } else if (eql(field.type, "[]const u8")) {
                                pos = writeStr(&buffer, pos, "\"\"");
                            } else if (eql(field.type, "bool")) {
                                pos = writeStr(&buffer, pos, "false");
                            } else {
                                pos = writeStr(&buffer, pos, "undefined");
                            }
                            pos = writeStr(&buffer, pos, ",");
                        }
                        
                        pos = writeStr(&buffer, pos, "} };\n");
                    } else {
                        pos = writeStr(&buffer, pos, "            return undefined;\n");
                    }
                }
                
                pos = writeStr(&buffer, pos, "        }\n");
                
                // Close the event struct
                pos = writeStr(&buffer, pos, "    };\n");
            },
            else => {},
        }
    }
    
    // Generate simple tap registry (placeholder for now) - inside main_module
    pos = writeStr(&buffer, pos, "\n    // Event Tap Registry (placeholder)\n");
    pos = writeStr(&buffer, pos, "    const TapRegistry = struct {\n");
    pos = writeStr(&buffer, pos, "        pub fn invokeInputTaps(event_name: []const u8, input: anytype) void {\n");
    pos = writeStr(&buffer, pos, "            // TODO: Implement tap lookup and invocation\n");
    pos = writeStr(&buffer, pos, "            _ = event_name;\n");
    pos = writeStr(&buffer, pos, "            _ = input;\n");
    pos = writeStr(&buffer, pos, "        }\n");
    pos = writeStr(&buffer, pos, "        pub fn invokeOutputTaps(event_name: []const u8, output: anytype) void {\n");
    pos = writeStr(&buffer, pos, "            // TODO: Implement tap lookup and invocation\n");
    pos = writeStr(&buffer, pos, "            _ = event_name;\n");
    pos = writeStr(&buffer, pos, "            _ = output;\n");
    pos = writeStr(&buffer, pos, "        }\n");
    pos = writeStr(&buffer, pos, "    };\n");

    // Collect all event taps for injection at transition points
    var tap_count: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .event_tap => {
                tap_count += 1;
            },
            else => {},
        }
    }

    // Generate tap helper functions (one per tap)
    var tap_counter: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .event_tap => |tap| {
                // Check if this tap uses transition binding
                var has_transition_binding = false;
                var has_branch_binding = false;
                if (tap.continuations.len > 0) {
                    if (tap.continuations[0].binding_type == .transition) {
                        has_transition_binding = true;
                    } else if (tap.continuations[0].binding) |_| {
                        has_branch_binding = true;
                    }
                }

                // Generate tap function with __tap prefix to avoid name conflicts
                pos = writeStr(&buffer, pos, "    fn __tap");
                var tap_num_buf: [32]u8 = undefined;
                const tap_num_str = std.fmt.bufPrint(&tap_num_buf, "{}", .{tap_counter}) catch "ERROR";
                pos = writeStr(&buffer, pos, tap_num_str);
                pos = writeStr(&buffer, pos, "(");

                // Add parameter based on binding type
                if (has_transition_binding) {
                    if (tap.continuations[0].binding) |binding| {
                        pos = writeStr(&buffer, pos, binding);
                        pos = writeStr(&buffer, pos, ": ");

                        // Determine type name based on annotations
                        if (tap.annotations.len == 0) {
                            pos = writeStr(&buffer, pos, "Transition");
                        } else {
                            // Check for profiling annotation
                            var has_profiling = false;
                            for (tap.annotations) |ann| {
                                if (eql(ann, "profiling")) {
                                    has_profiling = true;
                                }
                            }
                            if (has_profiling) {
                                pos = writeStr(&buffer, pos, "Transition_profiling");
                            } else {
                                pos = writeStr(&buffer, pos, "Transition");
                            }
                        }
                    }
                } else if (has_branch_binding) {
                    // Branch payload binding - use anytype for simplicity
                    if (tap.continuations[0].binding) |binding| {
                        pos = writeStr(&buffer, pos, binding);
                        pos = writeStr(&buffer, pos, ": anytype");
                    }
                }

                pos = writeStr(&buffer, pos, ") void {\n");

                // Generate tap continuations with proper indentation and where clause
                if (tap.continuations.len > 0) {
                    // Add where clause check if present
                    if (tap.continuations[0].condition) |cond| {
                        pos = writeStr(&buffer, pos, "        if (");
                        pos = writeStr(&buffer, pos, cond);
                        pos = writeStr(&buffer, pos, ") {\n");
                        pos = generateContinuationBody(&buffer, pos, tap.continuations[0], "            ", e.ast.items, 0, TAP_FUNCTION_CONTEXT);
                        pos = writeStr(&buffer, pos, "        }\n");
                    } else {
                        pos = generateContinuationBody(&buffer, pos, tap.continuations[0], "        ", e.ast.items, 0, TAP_FUNCTION_CONTEXT);
                    }
                }

                pos = writeStr(&buffer, pos, "    }\n");
                tap_counter += 1;
            },
            else => {},
        }
    }

    // Continue with flows as functions (we're already inside main_module)

    var flow_counter: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .flow => |flow| {
                // Generate source marker for flow
                pos = writeStr(&buffer, pos, "    // >>> FLOW ");
                var flow_num_buf: [32]u8 = undefined;
                var flow_num_str = std.fmt.bufPrint(&flow_num_buf, "{}", .{flow_counter}) catch "N";
                pos = writeStr(&buffer, pos, flow_num_str);
                pos = writeStr(&buffer, pos, ": ");
                // Write invocation path
                for (flow.invocation.path, 0..) |segment, idx| {
                    if (idx > 0) pos = writeStr(&buffer, pos, ".");
                    pos = writeStr(&buffer, pos, segment);
                }
                pos = writeStr(&buffer, pos, "\n");

                // Check if this flow has a label - if so, we need a helper function for tail calls
                const has_label = flow.pre_label != null or flow.post_label != null;

                // Reuse flow_num_buf - recalculate for better error message on failure
                flow_num_str = std.fmt.bufPrint(&flow_num_buf, "{}", .{flow_counter}) catch "ERROR";

                if (has_label and flow.pre_label != null) {
                    // Generate parameterized helper function for labeled flow (can be tail-called)
                    // Need to find the event declaration for this flow's invocation to get parameter types
                    var found_event = false;

                    // Search for the event in both top-level and modules
                    for (e.ast.items) |evt_item| {
                        switch (evt_item) {
                            .event_decl => |event| {
                                if (event.path.len == flow.invocation.path.len) {
                                    var matches = true;
                                    for (event.path, 0..) |seg, j| {
                                        if (!eql(seg, flow.invocation.path[j])) {
                                            matches = false;
                                            break;
                                        }
                                    }
                                    if (matches) {
                                        // Found the event - generate parameterized helper function
                                        found_event = true;
                                        pos = writeStr(&buffer, pos, "    fn flow");
                                        pos = writeStr(&buffer, pos, flow_num_str);
                                        pos = writeStr(&buffer, pos, "_");
                                        pos = writeStr(&buffer, pos, flow.pre_label.?);
                                        pos = writeStr(&buffer, pos, "(");

                                        // Add parameters matching event input fields
                                        for (event.input.fields, 0..) |field, idx| {
                                            if (idx > 0) {
                                                pos = writeStr(&buffer, pos, ", ");
                                            }
                                            pos = writeStr(&buffer, pos, field.name);
                                            pos = writeStr(&buffer, pos, ": ");
                                            if (field.is_file or field.is_embed_file) {
                                                pos = writeStr(&buffer, pos, "[]const u8");
                                            } else {
                                                pos = writeStr(&buffer, pos, field.type);
                                            }
                                        }

                                        pos = writeStr(&buffer, pos, ") void {\n");
                                        break;
                                    }
                                }
                            },
                            .module_decl => |module| {
                                for (module.items) |mod_item| {
                                    switch (mod_item) {
                                        .event_decl => |event| {
                                            if (event.path.len == flow.invocation.path.len) {
                                                var matches = true;
                                                for (event.path, 0..) |seg, j| {
                                                    if (!eql(seg, flow.invocation.path[j])) {
                                                        matches = false;
                                                        break;
                                                    }
                                                }
                                                if (matches) {
                                                    // Found the event - generate parameterized helper function
                                                    found_event = true;
                                                    pos = writeStr(&buffer, pos, "    fn flow");
                                                    pos = writeStr(&buffer, pos, flow_num_str);
                                                    pos = writeStr(&buffer, pos, "_");
                                                    pos = writeStr(&buffer, pos, flow.pre_label.?);
                                                    pos = writeStr(&buffer, pos, "(");

                                                    // Add parameters matching event input fields
                                                    for (event.input.fields, 0..) |field, idx| {
                                                        if (idx > 0) {
                                                            pos = writeStr(&buffer, pos, ", ");
                                                        }
                                                        pos = writeStr(&buffer, pos, field.name);
                                                        pos = writeStr(&buffer, pos, ": ");
                                                        if (field.is_file or field.is_embed_file) {
                                                            pos = writeStr(&buffer, pos, "[]const u8");
                                                        } else {
                                                            pos = writeStr(&buffer, pos, field.type);
                                                        }
                                                    }

                                                    pos = writeStr(&buffer, pos, ") void {\n");
                                                    break;
                                                }
                                            }
                                        },
                                        else => {},
                                    }
                                }
                            },
                            else => {},
                        }
                        if (found_event) break;
                    }

                    // Fallback if event not found (shouldn't happen in valid code)
                    if (!found_event) {
                        pos = writeStr(&buffer, pos, "    fn flow");
                        pos = writeStr(&buffer, pos, flow_num_str);
                        pos = writeStr(&buffer, pos, "_");
                        pos = writeStr(&buffer, pos, flow.pre_label.?);
                        pos = writeStr(&buffer, pos, "() void {\n");
                    }
                } else {
                    pos = writeStr(&buffer, pos, "    pub fn flow");
                    pos = writeStr(&buffer, pos, flow_num_str);
                    pos = writeStr(&buffer, pos, "() void {\n");
                }
                
                // Generate the flow body
                // Check if any tap on this event has [profiling] annotation
                var needs_profiling = false;
                for (e.ast.items) |tap_item| {
                    switch (tap_item) {
                        .event_tap => |tap| {
                            // Check if tap source matches this flow's event
                            var source_matches = false;
                            if (tap.source) |src| {
                                if (src.segments.len == flow.invocation.path.len) {
                                    source_matches = true;
                                    for (src.segments, 0..) |segment, idx| {
                                        if (!eql(segment, flow.invocation.path[idx])) {
                                            source_matches = false;
                                            break;
                                        }
                                    }
                                }
                            }

                            if (source_matches) {
                                // Check for profiling annotation
                                for (tap.annotations) |ann| {
                                    if (eql(ann, "profiling")) {
                                        needs_profiling = true;
                                        break;
                                    }
                                }
                            }
                        },
                        else => {},
                    }
                    if (needs_profiling) break;
                }

                // TODO: Add input tap injection here when tap registry is ready
                // For now, we just generate a comment placeholder
                pos = writeStr(&buffer, pos, "        // [TAP INJECTION POINT: INPUT]\n");

                // If profiling is needed, start timing
                if (needs_profiling) {
                    pos = writeStr(&buffer, pos, "        const start_time = std.time.nanoTimestamp();\n");
                }

                // For void events (no continuations), don't assign to a variable
                if (flow.continuations.len > 0) {
                    pos = writeStr(&buffer, pos, "        const result = ");
                } else {
                    pos = writeStr(&buffer, pos, "        ");
                }
                
                // Check if this event is in a module or main
                var event_module: ?[]const u8 = null;
                
                // First check modules
                for (e.ast.items) |evt_item| {
                    switch (evt_item) {
                        .module_decl => |module| {
                            for (module.items) |mod_item| {
                                switch (mod_item) {
                                    .event_decl => |event| {
                                        if (event.path.len == flow.invocation.path.len) {
                                            var matches = true;
                                            for (event.path, 0..) |seg, j| {
                                                if (!eql(seg, flow.invocation.path[j])) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            if (matches) {
                                                event_module = module.logical_name;
                                                break;
                                            }
                                        }
                                    },
                                    else => {},
                                }
                            }
                            if (event_module != null) break;
                        },
                        else => {},
                    }
                }
                
                // Use module prefix if imported, otherwise local
                if (event_module) |mod| {
                    pos = writeStr(&buffer, pos, mod);
                    pos = writeStr(&buffer, pos, ".");
                    pos = writeStr(&buffer, pos, flow.invocation.path[flow.invocation.path.len - 1]);
                } else {
                    pos = writeStr(&buffer, pos, flow.invocation.path[flow.invocation.path.len - 1]);
                }
                pos = writeStr(&buffer, pos, ".handler(.{");

                // For labeled flows, use parameters instead of hardcoded values
                if (has_label and flow.pre_label != null) {
                    // Use parameters from helper function
                    for (flow.invocation.args, 0..) |arg, i| {
                        if (i > 0) pos = writeStr(&buffer, pos, ", ");
                        pos = writeStr(&buffer, pos, " .");
                        pos = writeStr(&buffer, pos, arg.name);
                        pos = writeStr(&buffer, pos, " = ");
                        // Use parameter name instead of hardcoded value
                        pos = writeStr(&buffer, pos, arg.name);
                    }
                } else {
                    // Non-labeled flows use hardcoded values from invocation
                    for (flow.invocation.args, 0..) |arg, i| {
                        if (i > 0) pos = writeStr(&buffer, pos, ", ");
                        pos = writeStr(&buffer, pos, " .");
                        pos = writeStr(&buffer, pos, arg.name);
                        pos = writeStr(&buffer, pos, " = ");
                        pos = writeStr(&buffer, pos, arg.value);
                    }
                }
                pos = writeStr(&buffer, pos, " });\n");

                // If profiling is needed, end timing and calculate duration
                if (needs_profiling) {
                    pos = writeStr(&buffer, pos, "        const end_time = std.time.nanoTimestamp();\n");
                    pos = writeStr(&buffer, pos, "        const duration_ns = @as(u64, @intCast(end_time - start_time));\n");
                }

                // TODO: Add output tap injection here when tap registry is ready
                pos = writeStr(&buffer, pos, "        // [TAP INJECTION POINT: OUTPUT]\n");

                // Generate continuation handling
                // For void events (no continuations), skip the switch
                if (flow.continuations.len > 0) {
                pos = writeStr(&buffer, pos, "        switch (result) {\n");
                
                // Group continuations by branch name
                var i: usize = 0;
                while (i < flow.continuations.len) {
                    const branch_name = flow.continuations[i].branch;
                    
                    // Count how many continuations have this branch name
                    var same_branch_count: usize = 1;
                    while (i + same_branch_count < flow.continuations.len) {
                        if (!eql(flow.continuations[i + same_branch_count].branch, branch_name)) break;
                        same_branch_count += 1;
                    }
                    
                    pos = writeStr(&buffer, pos, "            .");
                    pos = writeStr(&buffer, pos, branch_name);
                    pos = writeStr(&buffer, pos, " => ");

                    // Check if any tap needs branch payload for this branch
                    var tap_needs_payload = false;
                    for (e.ast.items) |tap_check_item| {
                        switch (tap_check_item) {
                            .event_tap => |tap_check| {
                                for (tap_check.continuations) |tap_cont_check| {
                                    if (eql(tap_cont_check.branch, branch_name) and tap_cont_check.binding != null and tap_cont_check.binding_type == .branch_payload) {
                                        tap_needs_payload = true;
                                        break;
                                    }
                                }
                                if (tap_needs_payload) break;
                            },
                            else => {},
                        }
                    }

                    // Get binding from first continuation with this branch, or generate one if tap needs it
                    var binding_name: []const u8 = "_tap_payload";
                    var has_user_binding = false;
                    if (flow.continuations[i].binding) |binding| {
                        binding_name = binding;
                        has_user_binding = true;
                    }

                    // Generate binding capture if user specified one OR if tap needs it
                    if (has_user_binding or tap_needs_payload) {
                        pos = writeStr(&buffer, pos, "|");
                        pos = writeStr(&buffer, pos, binding_name);
                        pos = writeStr(&buffer, pos, "| {\n");
                    } else {
                        pos = writeStr(&buffer, pos, "{\n");
                    }

                    // INJECT TAP CALLS HERE!
                    // Skip tap injection if we're generating a tap function itself
                    // This prevents infinite recursion
                    if (flow_counter != TAP_FUNCTION_CONTEXT) {
                    // For each tap that matches: source_event -> * | branch_name
                    // We need to call the tap function
                    var tap_idx: usize = 0;
                    for (e.ast.items) |tap_item| {
                        switch (tap_item) {
                            .event_tap => |tap| {
                                // Check if this tap matches current transition
                                // Source must match current event (flow.invocation.path)
                                var source_matches = false;
                                if (tap.source) |src| {
                                    if (src.segments.len == flow.invocation.path.len) {
                                        source_matches = true;
                                        for (src.segments, 0..) |segment, idx| {
                                            if (!eql(segment, flow.invocation.path[idx])) {
                                                source_matches = false;
                                                break;
                                            }
                                        }
                                    }
                                } else {
                                    // null source = wildcard (*)
                                    source_matches = true;
                                }

                                // Check if tap has continuation for this branch
                                var has_branch = false;
                                if (source_matches) {
                                    for (tap.continuations) |tap_cont| {
                                        if (eql(tap_cont.branch, branch_name)) {
                                            has_branch = true;
                                            break;
                                        }
                                    }
                                }

                                // If matches, inject tap call
                                if (has_branch) {
                                    // Check what parameter type tap needs
                                    var tap_needs_transition = false;
                                    var tap_needs_branch_payload = false;
                                    for (tap.continuations) |tap_cont| {
                                        if (tap_cont.binding_type == .transition) {
                                            tap_needs_transition = true;
                                            break;
                                        } else if (tap_cont.binding) |_| {
                                            tap_needs_branch_payload = true;
                                            break;
                                        }
                                    }

                                    pos = writeStr(&buffer, pos, "                __tap");
                                    var tap_idx_buf: [32]u8 = undefined;
                                    const tap_idx_str = std.fmt.bufPrint(&tap_idx_buf, "{}", .{tap_idx}) catch "ERROR";
                                    pos = writeStr(&buffer, pos, tap_idx_str);
                                    pos = writeStr(&buffer, pos, "(");

                                    // Pass appropriate parameter based on tap binding type
                                    if (tap_needs_transition) {
                                        pos = writeStr(&buffer, pos, ".{ .source = \"");
                                        // Write source event name
                                        for (flow.invocation.path, 0..) |seg, seg_idx| {
                                            if (seg_idx > 0) pos = writeStr(&buffer, pos, ".");
                                            pos = writeStr(&buffer, pos, seg);
                                        }
                                        pos = writeStr(&buffer, pos, "\", .branch = \"");
                                        pos = writeStr(&buffer, pos, branch_name);
                                        pos = writeStr(&buffer, pos, "\", .destination = ");

                                        // Determine destination from continuation pipeline
                                        const cont = flow.continuations[i];
                                        var has_destination = false;
                                        if (cont.pipeline.len > 0) {
                                            switch (cont.pipeline[0]) {
                                                .invocation => |inv| {
                                                    // Check if it's not terminal (_)
                                                    if (inv.path.len > 0 and !eql(inv.path[0], "_")) {
                                                        has_destination = true;
                                                        pos = writeStr(&buffer, pos, "\"");
                                                        for (inv.path, 0..) |seg, seg_idx| {
                                                            if (seg_idx > 0) pos = writeStr(&buffer, pos, ".");
                                                            pos = writeStr(&buffer, pos, seg);
                                                        }
                                                        pos = writeStr(&buffer, pos, "\"");
                                                    }
                                                },
                                                else => {},
                                            }
                                        }
                                        if (!has_destination) {
                                            pos = writeStr(&buffer, pos, "null");
                                        }

                                        // Add profiling field if tap has [profiling] annotation
                                        var tap_has_profiling = false;
                                        for (tap.annotations) |ann| {
                                            if (eql(ann, "profiling")) {
                                                tap_has_profiling = true;
                                                break;
                                            }
                                        }
                                        if (tap_has_profiling) {
                                            pos = writeStr(&buffer, pos, ", .duration_ns = duration_ns");
                                        }

                                        pos = writeStr(&buffer, pos, " }");
                                    } else if (tap_needs_branch_payload) {
                                        // Pass the branch payload binding (either user-specified or auto-generated)
                                        pos = writeStr(&buffer, pos, binding_name);
                                    }

                                    pos = writeStr(&buffer, pos, ");\n");
                                }

                                tap_idx += 1;
                            },
                            else => {},
                        }
                    }
                    } // End of tap injection if statement

                    // If there are multiple continuations with same branch, generate if-else chain
                    if (same_branch_count > 1) {
                        var j: usize = 0;
                        while (j < same_branch_count) {
                            const cont = flow.continuations[i + j];
                            
                            if (cont.condition) |cond| {
                                if (j == 0) {
                                    pos = writeStr(&buffer, pos, "                if (");
                                } else {
                                    pos = writeStr(&buffer, pos, "                } else if (");
                                }
                                
                                // Generate condition expression
                                // Simple replacement of binding references
                                var cond_pos: usize = 0;
                                while (cond_pos < cond.len) {
                                    // Check if we're at the start of the binding name
                                    if (cont.binding) |binding| {
                                        if (cond_pos + binding.len <= cond.len) {
                                            var matches = true;
                                            for (binding, 0..) |ch, idx| {
                                                if (cond[cond_pos + idx] != ch) {
                                                    matches = false;
                                                    break;
                                                }
                                            }
                                            
                                            // Check it's a word boundary
                                            if (matches) {
                                                const after = if (cond_pos + binding.len < cond.len) cond[cond_pos + binding.len] else 0;
                                                const before = if (cond_pos > 0) cond[cond_pos - 1] else 0;
                                                const is_word_boundary = (before < 'a' or before > 'z') and 
                                                                        (before < 'A' or before > 'Z') and
                                                                        (before < '0' or before > '9') and
                                                                        before != '_' and
                                                                        (after < 'a' or after > 'z') and
                                                                        (after < 'A' or after > 'Z') and
                                                                        (after < '0' or after > '9') and
                                                                        after != '_';
                                                
                                                if (is_word_boundary) {
                                                    // Write the binding variable
                                                    pos = writeStr(&buffer, pos, binding);
                                                    cond_pos += binding.len;
                                                    continue;
                                                }
                                            }
                                        }
                                    }
                                    
                                    // Copy the character as-is
                                    var char_buf: [1]u8 = .{cond[cond_pos]};
                                    pos = writeStr(&buffer, pos, &char_buf);
                                    cond_pos += 1;
                                }
                                
                                pos = writeStr(&buffer, pos, ") {\n");
                                
                                // Generate the continuation body with extra indent
                                pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items, 0, flow_counter);
                            } else {
                                // No condition - this is the default/else case
                                if (j > 0) {
                                    pos = writeStr(&buffer, pos, "                } else {\n");
                                    pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items, 0, flow_counter);
                                } else {
                                    // Single continuation without condition
                                    pos = generateContinuationBody(&buffer, pos, cont, "                ", e.ast.items, 0, flow_counter);
                                }
                            }
                            j += 1;
                        }
                        
                        // Close the if-else chain if we had conditions
                        if (flow.continuations[i].condition != null) {
                            pos = writeStr(&buffer, pos, "                }\n");
                        }
                    } else {
                        // Single continuation for this branch
                        const cont = flow.continuations[i];
                        if (cont.condition) |cond| {
                            // Generate if statement for single where clause
                            pos = writeStr(&buffer, pos, "                if (");
                            
                            // Write condition (with simple binding replacement)
                            var cond_pos: usize = 0;
                            while (cond_pos < cond.len) {
                                var char_buf: [1]u8 = .{cond[cond_pos]};
                                pos = writeStr(&buffer, pos, &char_buf);
                                cond_pos += 1;
                            }
                            
                            pos = writeStr(&buffer, pos, ") {\n");
                            pos = generateContinuationBody(&buffer, pos, cont, "                    ", e.ast.items, 0, flow_counter);
                            pos = writeStr(&buffer, pos, "                }\n");
                        } else {
                            // No condition
                            pos = generateContinuationBody(&buffer, pos, cont, "                ", e.ast.items, 0, flow_counter);
                        }
                    }
                    
                    pos = writeStr(&buffer, pos, "            },\n");
                    
                    // Move to next set of branches
                    i += same_branch_count;
                }

                pos = writeStr(&buffer, pos, "        }\n");
                } // End of if (flow.continuations.len > 0)
                pos = writeStr(&buffer, pos, "    }\n");

                // If this flow had a pre_label, generate the public wrapper that calls the helper
                if (has_label and flow.pre_label != null) {
                    pos = writeStr(&buffer, pos, "\n    pub fn flow");
                    pos = writeStr(&buffer, pos, flow_num_str);  // Reuse flow_num_str from above
                    pos = writeStr(&buffer, pos, "() void {\n");
                    pos = writeStr(&buffer, pos, "        flow");
                    pos = writeStr(&buffer, pos, flow_num_str);
                    pos = writeStr(&buffer, pos, "_");
                    pos = writeStr(&buffer, pos, flow.pre_label.?);
                    pos = writeStr(&buffer, pos, "(");

                    // Pass initial arguments from flow invocation
                    for (flow.invocation.args, 0..) |arg, arg_idx| {
                        if (arg_idx > 0) {
                            pos = writeStr(&buffer, pos, ", ");
                        }
                        pos = writeStr(&buffer, pos, arg.value);
                    }

                    pos = writeStr(&buffer, pos, ");\n");
                    pos = writeStr(&buffer, pos, "    }\n");
                }

                pos = writeStr(&buffer, pos, "\n");

                flow_counter += 1;
            },
            else => {},
        }
    }
    
    // Close the main_module struct
    pos = writeStr(&buffer, pos, "};\n\n");
    
    // Generate minimal main function that calls flows from main_module
    pos = writeStr(&buffer, pos, "pub fn main() void {\n");
    
    var flow_count: usize = 0;
    for (e.ast.items) |item| {
        switch (item) {
            .flow => {
                pos = writeStr(&buffer, pos, "    main_module.flow");
                var main_num_buf: [32]u8 = undefined;
                const main_num_str = std.fmt.bufPrint(&main_num_buf, "{}", .{flow_count}) catch "ERROR";
                pos = writeStr(&buffer, pos, main_num_str);
                pos = writeStr(&buffer, pos, "();\n");
                flow_count += 1;
            },
            else => {},
        }
    }
    
    pos = writeStr(&buffer, pos, "}\n");
    
    // Return the emitted code!
    const final_code = buffer[0..pos];
    return .{ .emitted = .{ .code = final_code } };
    }
};

const compiler_passes_evaluate_comptime = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) { evaluated: struct { ast: *const SourceFile, events_executed: usize } };
    pub fn handler(e: Input) Output {

    // Phase 1: Build map of comptime-only events
    // (Events that have FlowAST, ProgramAST, or Source parameters)
    var comptime_events: [64][]const u8 = undefined;
    var comptime_count: usize = 0;

    for (e.ast.items) |item| {
        switch (item) {
            .event_decl => |event_decl| {
                // Check if this event has comptime-only parameters
                var is_comptime = false;
                for (event_decl.input.fields) |field| {
                    if (field.is_flow_ast or field.is_source) {
                        is_comptime = true;
                        break;
                    }
                    if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "SourceFile")) {
                        is_comptime = true;
                        break;
                    }
                }

                if (is_comptime and comptime_count < 64) {
                    // Build event name from path segments
                    const event_name = joinPath(event_decl.path);
                    comptime_events[comptime_count] = event_name;
                    comptime_count += 1;
                }
            },
            .module_decl => |module| {
                // Also check imported modules
                for (module.items) |mod_item| {
                    if (mod_item == .event_decl) {
                        const event_decl = mod_item.event_decl;
                        var is_comptime = false;
                        for (event_decl.input.fields) |field| {
                            if (field.is_flow_ast or field.is_source) {
                                is_comptime = true;
                                break;
                            }
                            if (std.mem.eql(u8, field.type, "ProgramAST") or std.mem.eql(u8, field.type, "SourceFile")) {
                                is_comptime = true;
                                break;
                            }
                        }

                        if (is_comptime and comptime_count < 64) {
                            const event_name = joinPath(event_decl.path);
                            comptime_events[comptime_count] = event_name;
                            comptime_count += 1;
                        }
                    }
                }
            },
            else => {},
        }
    }

    // Phase 2: Walk flows and find comptime event invocations
    var invocations_found: usize = 0;

    // std.debug.print("  Phase 2: Scanning flows for comptime invocations...\n", .{});
    for (e.ast.items) |item| {
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path);
            // std.debug.print("    Flow invokes: {s}\n", .{inv_path});

            // Check if this invocation is to a comptime event
            var i: usize = 0;
            while (i < comptime_count) : (i += 1) {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    // Found a comptime event invocation!
                    // std.debug.print("  ✓ Found comptime invocation: {s}\n", .{inv_path});

                    // Call the comptime handler!
                    const handler_result = callComptimeHandler(inv_path, e.ast);

                    // For now, just print that we called it
                    // TODO: Use result to transform flow/AST
                    switch (handler_result) {
                        .none => {
                            // std.debug.print("  WARNING: Handler not found for: {s}\n", .{inv_path});
                        },
                        else => {
                            // std.debug.print("  ✓ Executed comptime handler: {s}\n", .{inv_path});
                            invocations_found += 1;
                        },
                    }

                    break;
                }
            }
        }
    }

    // std.debug.print("  Detected {} comptime events, {} invocations\n", .{comptime_count, invocations_found});

    // Phase 3: Build new AST without comptime flows and [raw] procs (AST TRANSFORMATION!)
    // Count non-comptime items first
    comptime var count_non_comptime: usize = 0;
    inline for (e.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path);

            // Check if comptime flow
            inline for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path);
                var is_comptime = false;
                inline for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            count_non_comptime += 1;
        }
    }

    // Build new array with exact size
    var new_items: [count_non_comptime]Item = undefined;
    var idx: usize = 0;
    inline for (e.ast.items) |item| {
        var should_keep = true;
        if (item == .flow) {
            const flow = item.flow;
            const inv_path = joinPath(flow.invocation.path);

            // Check if comptime flow
            inline for (0..comptime_count) |i| {
                if (std.mem.eql(u8, inv_path, comptime_events[i])) {
                    should_keep = false;
                    break;
                }
            }
        }

        // Filter out [raw] procs that are NOT comptime procs
        if (item == .proc_decl) {
            const proc = item.proc_decl;

            // Check if proc has [raw] annotation
            var has_raw = false;
            for (proc.annotations) |ann| {
                if (std.mem.eql(u8, ann, "raw")) {
                    has_raw = true;
                    break;
                }
            }

            if (has_raw) {
                // Check if this proc is comptime (in comptime_events list)
                const proc_path = joinPath(proc.path);
                var is_comptime = false;
                inline for (0..comptime_count) |i| {
                    if (std.mem.eql(u8, proc_path, comptime_events[i])) {
                        is_comptime = true;
                        break;
                    }
                }

                // If [raw] but NOT comptime, remove it
                if (!is_comptime) {
                    should_keep = false;
                }
            }
        }

        if (should_keep) {
            new_items[idx] = item;
            idx += 1;
        }
    }

    const transformed_ast = SourceFile{
        .items = &new_items,
    };

    return .{ .evaluated = .{
        .ast = &transformed_ast,
        .events_executed = invocations_found
    } };
    }
};

// Helper: Join path segments with dots
const joinPath = struct {
    fn call(path: []const []const u8) []const u8 {
        if (path.len == 0) return "";
        if (path.len == 1) return path[0];
        var total_len: usize = path[0].len;
        var i: usize = 1;
        while (i < path.len) : (i += 1) {
            total_len += 1 + path[i].len;
        }
        var result: [256]u8 = undefined;
        var pos: usize = 0;
        @memcpy(result[pos..pos + path[0].len], path[0]);
        pos += path[0].len;
        i = 1;
        while (i < path.len) : (i += 1) {
            result[pos] = '.';
            pos += 1;
            @memcpy(result[pos..pos + path[i].len], path[i]);
            pos += path[i].len;
        }
        return result[0..pos];
    }
}.call;

// === USER COMPTIME HANDLERS ===
// These handlers execute at compile-time (Zig comptime) to transform the AST

// Comptime Handler Dispatcher
// Maps runtime handler names to actual handler calls
const ComptimeHandlerResult = union(enum) {
    none: void,
};

fn callComptimeHandler(name: []const u8, ast: *const SourceFile) ComptimeHandlerResult {
    _ = name;
    _ = ast;
    return .{ .none = {} };
}

// Bootstrap coordinator - calls evaluate_comptime then emitter!
const compiler_coordinate_default = struct {
    pub const Input = struct { ast: *const SourceFile };
    pub const Output = union(enum) {
        coordinated: struct {
            ast: *const SourceFile,
            code: []const u8,
            metrics: []const u8,
        },
    };

    pub fn handler(e: Input) Output {
        // First, run comptime evaluation pass to transform the AST
        const eval_result = compiler_passes_evaluate_comptime.handler(.{ .ast = e.ast });

        // Then emit code from the TRANSFORMED AST
        const emit_result = compiler_emit_zig.handler(.{ .ast = eval_result.evaluated.ast });

        return .{ .coordinated = .{
            .ast = eval_result.evaluated.ast,
            .code = emit_result.emitted.code,
            .metrics = "Metacircular compilation complete!",
        }};
    }
};
// Compile-time code generation
const ComptimeEmitter = struct {
    pub fn emit(ast: *const SourceFile) [64*1024]u8 {
        @setEvalBranchQuota(100000);  // Increase branch quota for complex ASTs
        const result = compiler_coordinate_default.handler(.{ .ast = ast });
        var buf: [64*1024]u8 = [_]u8{0} ** (64*1024);
        const copy_len = @min(result.coordinated.code.len, 64*1024);
        @memcpy(buf[0..copy_len], result.coordinated.code[0..copy_len]);
        return buf;
    }
};

// Generate code at compile-time from the AST
const generated_code_buffer = ComptimeEmitter.emit(&PROGRAM_AST);
// For now, just use the full buffer - we'll trim zeros at runtime
const generated_code = generated_code_buffer[0..];

// Standard library import for the backend
const std = @import("std");
// === KORU BACKEND CODE GENERATOR ===
// This outputs the final Zig code generated by compiler.emit.zig

pub fn main() !void {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    const allocator = gpa.allocator();
    defer _ = gpa.deinit();
    
    // Get the output filename from argv (passed from koruc)
    const args = try std.process.argsAlloc(allocator);
    defer std.process.argsFree(allocator, args);
    
    // Default output names
    const emitted_file = "output_emitted.zig";
    const output_exe = if (args.len > 1) args[1] else "a.out";
    
    // Find actual length (trim trailing zeros)
    var actual_len: usize = generated_code.len;
    while (actual_len > 0 and generated_code[actual_len - 1] == 0) {
        actual_len -= 1;
    }
    const trimmed_code = generated_code[0..actual_len];
    
    // Write the generated code to a file
    const file = try std.fs.cwd().createFile(emitted_file, .{});
    defer file.close();
    try file.writeAll(trimmed_code);
    
    // Report what we generated
    const stdout = std.fs.File.stdout();
    var buf: [512]u8 = undefined;
    const msg = try std.fmt.bufPrint(&buf, "✓ Generated {s} ({d} bytes)\n", .{emitted_file, actual_len});
    try stdout.writeAll(msg);
    
    // Now compile the emitted code  
    var emit_path_buf: [256]u8 = undefined;
    const emit_path = try std.fmt.bufPrint(&emit_path_buf, "-femit-bin={s}", .{output_exe});
    const argv = [_][]const u8{ "zig", "build-exe", emitted_file, emit_path };
    const result = std.process.Child.run(.{
        .allocator = allocator,
        .argv = &argv,
    }) catch |err| {
        const stderr = std.fs.File.stderr();
        var err_buf: [512]u8 = undefined;
        const err_msg = try std.fmt.bufPrint(&err_buf, "✗ Failed to spawn zig compiler: {}\n", .{err});
        try stderr.writeAll(err_msg);
        std.process.exit(1);
    };
    defer allocator.free(result.stdout);
    defer allocator.free(result.stderr);
    
    const stdout2 = std.fs.File.stdout();
    var buf2: [512]u8 = undefined;
    if (result.term.Exited == 0) {
        const msg2 = try std.fmt.bufPrint(&buf2, "✓ Compiled to {s}\n", .{output_exe});
        try stdout2.writeAll(msg2);
    } else {
        const msg2 = try std.fmt.bufPrint(&buf2, "✗ Compilation failed\n", .{});
        try stdout2.writeAll(msg2);
        if (result.stderr.len > 0) {
            var err_buf2: [1024]u8 = undefined;
            const err_msg2 = try std.fmt.bufPrint(&err_buf2, "Error: {s}\n", .{result.stderr});
            try std.fs.File.stderr().writeAll(err_msg2);
        }
        std.process.exit(1);
    }
}